import{_ as t,c as s,o as a,a1 as e}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"快速開始：5分鐘上手 opencode-notify | opencode-notify 教學","description":"學習如何安裝 opencode-notify 外掛程式，在5分鐘內完成設定並體驗第一個桌面通知。本教學涵蓋 OCX 套件管理器安裝和手動安裝兩種方式，支援 macOS、Windows 和 Linux 系統，幫助您在 AI 任務完成時及時收到提醒。","frontmatter":{"title":"快速開始：5分鐘上手 opencode-notify | opencode-notify 教學","sidebarTitle":"5 分鐘收到通知","subtitle":"快速開始：5分鐘上手 opencode-notify","description":"學習如何安裝 opencode-notify 外掛程式，在5分鐘內完成設定並體驗第一個桌面通知。本教學涵蓋 OCX 套件管理器安裝和手動安裝兩種方式，支援 macOS、Windows 和 Linux 系統，幫助您在 AI 任務完成時及時收到提醒。","tags":["入門","安裝","快速上手"],"prerequisite":[],"order":10},"headers":[],"relativePath":"zh-tw/kdcokenny/opencode-notify/start/quick-start/index.md","filePath":"zh-tw/kdcokenny/opencode-notify/start/quick-start/index.md"}'),n={name:"zh-tw/kdcokenny/opencode-notify/start/quick-start/index.md"};function o(l,i,d,r,h,p){return a(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="快速開始-5分鐘上手-opencode-notify" tabindex="-1">快速開始：5分鐘上手 opencode-notify <a class="header-anchor" href="#快速開始-5分鐘上手-opencode-notify" aria-label="Permalink to &quot;快速開始：5分鐘上手 opencode-notify&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>3 分鐘內完成 opencode-notify 外掛程式安裝</li><li>觸發第一個桌面通知，驗證安裝成功</li><li>了解不同安裝方式的差異和適用情境</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>您委託 AI 完成一個任務後切換到其他視窗工作。現在你每隔 30 秒就切回去看一眼：完成了嗎？出錯了？還是在等權限？opencode-notify 正是為了解決這個問題而生的。</p><p>這種反覆切換既打斷思路，又浪費時間。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p><strong>在以下情境下啟用 opencode-notify</strong>：</p><ul><li>你經常在 AI 執行任務時切換到其他應用程式</li><li>你希望在 AI 需要你時被第一時間提醒</li><li>你想在保持專注的同時不錯過重要事件</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>opencode-notify 的工作原理很簡單：監聽 OpenCode 的事件，在關鍵時刻發送原生桌面通知。</p><p><strong>它會通知你</strong>：</p><ul><li>✅ 任務完成（Session idle）</li><li>✅ 執行出錯（Session error）</li><li>✅ 需要權限（Permission updated）</li></ul><p><strong>它不會通知你</strong>：</p><ul><li>❌ 每個子任務完成（太吵）</li><li>❌ 終端機聚焦時的任何事件（你在看終端機，不需要通知）</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置要求</p><ul><li>已安裝 <a href="https://github.com/sst/opencode" target="_blank" rel="noreferrer">OpenCode</a></li><li>有可用的終端機（macOS Terminal、iTerm2、Windows Terminal 等）</li><li>macOS/Windows/Linux 系統（三者均支援）</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-選擇安裝方式" tabindex="-1">第 1 步：選擇安裝方式 <a class="header-anchor" href="#第-1-步-選擇安裝方式" aria-label="Permalink to &quot;第 1 步：選擇安裝方式&quot;">​</a></h3><p>opencode-notify 提供兩種安裝方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>適用情境</th><th>優點</th><th>缺點</th></tr></thead><tbody><tr><td><strong>OCX 套件管理器</strong></td><td>大多數使用者</td><td>一鍵安裝、自動更新、相依套件管理完整</td><td>需要先安裝 OCX</td></tr><tr><td><strong>手動安裝</strong></td><td>特殊需求</td><td>完全控制、無需 OCX</td><td>需手動管理相依套件和更新</td></tr></tbody></table><p><strong>推薦</strong>：優先使用 OCX 安裝，更省心。</p><h3 id="第-2-步-透過-ocx-安裝-推薦" tabindex="-1">第 2 步：透過 OCX 安裝（推薦） <a class="header-anchor" href="#第-2-步-透過-ocx-安裝-推薦" aria-label="Permalink to &quot;第 2 步：透過 OCX 安裝（推薦）&quot;">​</a></h3><h4 id="_2-1-安裝-ocx-套件管理器" tabindex="-1">2.1 安裝 OCX 套件管理器 <a class="header-anchor" href="#_2-1-安裝-ocx-套件管理器" aria-label="Permalink to &quot;2.1 安裝 OCX 套件管理器&quot;">​</a></h4><p>OCX 是 OpenCode 的官方外掛程式套件管理器，可以方便地安裝、更新和管理外掛程式。</p><p><strong>安裝 OCX</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://ocx.kdco.dev/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><p><strong>你應該看到</strong>：安裝指令碼顯示進度，最後提示安裝成功。</p><h4 id="_2-2-新增-kdco-registry" tabindex="-1">2.2 新增 KDCO Registry <a class="header-anchor" href="#_2-2-新增-kdco-registry" aria-label="Permalink to &quot;2.2 新增 KDCO Registry&quot;">​</a></h4><p>KDCO Registry 是一個外掛程式倉庫，包含 opencode-notify 等多個實用外掛程式。</p><p><strong>新增 registry</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span></span></code></pre></div><p><strong>你應該看到</strong>：提示 &quot;Registry added successfully&quot; 或類似資訊。</p><div class="tip custom-block"><p class="custom-block-title">可選：全域設定</p><p>如果你想在所有專案中使用同一個 registry，新增 <code>--global</code> 參數：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span></span></code></pre></div></div><h4 id="_2-3-安裝-opencode-notify" tabindex="-1">2.3 安裝 opencode-notify <a class="header-anchor" href="#_2-3-安裝-opencode-notify" aria-label="Permalink to &quot;2.3 安裝 opencode-notify&quot;">​</a></h4><p><strong>安裝外掛程式</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/notify</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Added kdco/notify to your OpenCode workspace</span></span></code></pre></div><h3 id="第-3-步-一次性安裝整個工作區-可選" tabindex="-1">第 3 步：一次性安裝整個工作區（可選） <a class="header-anchor" href="#第-3-步-一次性安裝整個工作區-可選" aria-label="Permalink to &quot;第 3 步：一次性安裝整個工作區（可選）&quot;">​</a></h3><p>如果你想要完整的體驗，可以安裝 KDCO 工作區，它包含：</p><ul><li>opencode-notify（桌面通知）</li><li>背景代理（Background Agents）</li><li>專用代理（Specialist Agents）</li><li>規劃工具（Planning Tools）</li></ul><p><strong>安裝工作區</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/workspace</span></span></code></pre></div><p><strong>你應該看到</strong>：提示多個元件被成功新增。</p><h3 id="第-4-步-驗證安裝" tabindex="-1">第 4 步：驗證安裝 <a class="header-anchor" href="#第-4-步-驗證安裝" aria-label="Permalink to &quot;第 4 步：驗證安裝&quot;">​</a></h3><p>安裝完成後，我們需要觸發一個通知來驗證設定是否正確。</p><p><strong>驗證方法 1：讓 AI 完成一個任務</strong></p><p>在 OpenCode 中輸入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>請計算 1 到 10 的和，然後等待 5 秒後告訴我結果。</span></span></code></pre></div><p>切換到其他視窗工作幾秒後，你應該看到桌面通知彈出。</p><p><strong>驗證方法 2：檢查設定檔</strong></p><p>查看設定檔是否存在：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS/Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/kdco-notify.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows PowerShell</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:USERPROFILE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dco-notify.json</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>如果檔案不存在 → 說明使用預設設定（正常）</li><li>如果檔案存在 → 顯示你的自訂設定</li></ul><h3 id="第-5-步-手動安裝-備選方案" tabindex="-1">第 5 步：手動安裝（備選方案） <a class="header-anchor" href="#第-5-步-手動安裝-備選方案" aria-label="Permalink to &quot;第 5 步：手動安裝（備選方案）&quot;">​</a></h3><p>如果你不想使用 OCX，可以手動安裝。</p><h4 id="_5-1-複製原始碼" tabindex="-1">5.1 複製原始碼 <a class="header-anchor" href="#_5-1-複製原始碼" aria-label="Permalink to &quot;5.1 複製原始碼&quot;">​</a></h4><p>將 opencode-notify 的原始碼複製到 OpenCode 外掛程式目錄：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 從原始碼複製到獨立目錄</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/notify.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/plugin/kdco-primitives</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span></code></pre></div><h4 id="_5-2-安裝相依套件" tabindex="-1">5.2 安裝相依套件 <a class="header-anchor" href="#_5-2-安裝相依套件" aria-label="Permalink to &quot;5.2 安裝相依套件&quot;">​</a></h4><p>手動安裝必要的相依套件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node-notifier</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect-terminal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/sdk</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">注意事項</p><ul><li><strong>相依套件管理</strong>：需要手動安裝和更新 <code>node-notifier</code> 和 <code>detect-terminal</code></li><li><strong>更新困難</strong>：每次更新都需要手動重新複製原始碼</li><li><strong>不推薦</strong>：除非有特殊需求，建議使用 OCX 安裝</li></ul></div><h3 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h3><p>完成上述步驟後，請確認：</p><ul><li>[ ] OCX 安裝成功（<code>ocx --version</code> 能輸出版本號）</li><li>[ ] KDCO Registry 已新增（<code>ocx registry list</code> 顯示 kdco）</li><li>[ ] opencode-notify 已安裝（<code>ocx list</code> 顯示 kdco/notify）</li><li>[ ] 收到第一個桌面通知</li><li>[ ] 通知顯示正確的任務標題</li></ul><p><strong>如果某個步驟失敗</strong>：</p><ul><li>查看 <a href="./../../faq/troubleshooting/">故障排除</a> 取得協助</li><li>檢查 OpenCode 是否正常執行</li><li>確認你的系統支援桌面通知</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="常見問題-1-通知不顯示" tabindex="-1">常見問題 1：通知不顯示 <a class="header-anchor" href="#常見問題-1-通知不顯示" aria-label="Permalink to &quot;常見問題 1：通知不顯示&quot;">​</a></h3><p><strong>原因</strong>：</p><ul><li>macOS：系統通知被關閉</li><li>Windows：通知權限未授予</li><li>Linux：未安裝 notify-send</li></ul><p><strong>解決方法</strong>：</p><table tabindex="0"><thead><tr><th>平台</th><th>解決方法</th></tr></thead><tbody><tr><td>macOS</td><td>系統設定 → 通知 → OpenCode → 允許通知</td></tr><tr><td>Windows</td><td>設定 → 系統 → 通知 → 開啟通知</td></tr><tr><td>Linux</td><td>安裝 libnotify-bin：<code>sudo apt install libnotify-bin</code></td></tr></tbody></table><h3 id="常見問題-2-ocx-安裝失敗" tabindex="-1">常見問題 2：OCX 安裝失敗 <a class="header-anchor" href="#常見問題-2-ocx-安裝失敗" aria-label="Permalink to &quot;常見問題 2：OCX 安裝失敗&quot;">​</a></h3><p><strong>原因</strong>：網路問題或權限不足</p><p><strong>解決方法</strong>：</p><ol><li>檢查網路連線</li><li>使用 sudo 安裝（需要管理員權限）</li><li>手動下載安裝指令碼並執行</li></ol><h3 id="常見問題-3-相依套件安裝失敗" tabindex="-1">常見問題 3：相依套件安裝失敗 <a class="header-anchor" href="#常見問題-3-相依套件安裝失敗" aria-label="Permalink to &quot;常見問題 3：相依套件安裝失敗&quot;">​</a></h3><p><strong>原因</strong>：Node.js 版本不相容</p><p><strong>解決方法</strong>：</p><ul><li>使用 Node.js 18 或更高版本</li><li>清除 npm 快取：<code>npm cache clean --force</code></li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>本課我們完成了：</p><ul><li>✅ 安裝 OCX 套件管理器</li><li>✅ 新增 KDCO Registry</li><li>✅ 安裝 opencode-notify 外掛程式</li><li>✅ 觸發第一個桌面通知</li><li>✅ 了解手動安裝方法</li></ul><p><strong>關鍵要點</strong>：</p><ol><li>opencode-notify 使用原生桌面通知，無需頻繁切換視窗</li><li>OCX 是推薦的安裝方式，自動管理相依套件和更新</li><li>預設只通知父工作階段，避免子任務噪音</li><li>終端機聚焦時自動抑制通知</li></ol><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../how-it-works/">運作原理</a></strong>。</p><p>你會學到：</p><ul><li>外掛程式如何監聽 OpenCode 事件</li><li>智慧過濾機制的工作流程</li><li>終端機檢測和焦點感知的原理</li><li>不同平台的功能差異</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點選展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>外掛程式主入口</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L1-L407" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>1-407</td></tr><tr><td>設定載入</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>通知發送</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L280-L308" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>280-308</td></tr><tr><td>終端機檢測</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>靜音時段檢查</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>預設設定</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>DEFAULT_CONFIG.sounds.idle = &quot;Glass&quot;</code>：任務完成預設音效</li><li><code>DEFAULT_CONFIG.sounds.error = &quot;Basso&quot;</code>：錯誤預設音效</li><li><code>DEFAULT_CONFIG.sounds.permission = &quot;Submarine&quot;</code>：權限請求預設音效</li><li><code>DEFAULT_CONFIG.notifyChildSessions = false</code>：預設只通知父工作階段</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>NotifyPlugin()</code>：外掛程式入口函式，回傳事件處理器</li><li><code>loadConfig()</code>：載入設定檔，合併預設值</li><li><code>sendNotification()</code>：發送原生桌面通知</li><li><code>detectTerminalInfo()</code>：偵測終端機類型和 Bundle ID</li><li><code>isQuietHours()</code>：檢查目前時間是否在靜音時段</li><li><code>isParentSession()</code>：判斷是否為父工作階段</li><li><code>isTerminalFocused()</code>：偵測終端機是否為前景視窗</li></ul></details>`,94)])])}const g=t(n,[["render",o]]);export{k as __pageData,g as default};
